import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import type { User } from '@/data/initial-data';
import { getUsers, saveUsers, getAuth, setAuth } from '@/utils/storage';
import { ADMIN_USERNAME, ADMIN_PASSWORD } from '@/utils/constants';

interface AuthContextType {
  currentUser: User | null;
  login: (username: string, password: string) => boolean;
  register: (username: string, password: string) => boolean;
  logout: () => void;
  isAdmin: boolean;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  useEffect(() => {
    const auth = getAuth();
    if (auth.currentUser) {
      setCurrentUser(auth.currentUser);
    }
  }, []);

  const login = useCallback((username: string, password: string): boolean => {
    // Admin account
    if (username === ADMIN_USERNAME && password === ADMIN_PASSWORD) {
      const adminUser: User = {
        username: ADMIN_USERNAME,
        password: ADMIN_PASSWORD,
        role: 'admin',
        createdAt: new Date().toISOString(),
      };
      setCurrentUser(adminUser);
      setAuth(adminUser);
      return true;
    }

    // Regular users
    const users = getUsers();
    const user = users.find((u) => u.username === username && u.password === password);
    if (user) {
      setCurrentUser(user);
      setAuth(user);
      return true;
    }
    return false;
  }, []);

  const register = useCallback((username: string, password: string): boolean => {
    if (!username || !password || username === ADMIN_USERNAME) return false;
    const users = getUsers();
    if (users.some((u) => u.username === username)) return false;

    const newUser: User = {
      username,
      password,
      role: 'user',
      createdAt: new Date().toISOString(),
    };
    users.push(newUser);
    saveUsers(users);
    setCurrentUser(newUser);
    setAuth(newUser);
    return true;
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
    setAuth(null);
  }, []);

  const isAdmin = currentUser?.role === 'admin';

  return (
    <AuthContext.Provider value={{ currentUser, login, register, logout, isAdmin }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}
