import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, Save, CalendarDays } from 'lucide-react';
import LikeButton from '@/components/Interactions/LikeButton';
import CommentSection from '@/components/Interactions/CommentSection';
import { useAuth } from '@/context/AuthContext';
import { useData } from '@/context/DataContext';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';
import AnimatedButton from '@/components/Common/AnimatedButton';
import { exportDataToFile } from '@/utils/storage';

export default function Events() {
  const { isAdmin } = useAuth();
  const { data, updateData, saveToGitHub, hasToken, isSaving } = useData();
  const [editing, setEditing] = useState(false);
  const [newEvent, setNewEvent] = useState('');
  const [newDate, setNewDate] = useState(new Date().toISOString().split('T')[0]);

  const addEvent = () => {
    if (!newEvent.trim()) return;
    updateData((prev) => ({
      ...prev,
      events: [{ id: Date.now().toString(), date: newDate, content: newEvent.trim() }, ...prev.events],
    }));
    setNewEvent('');
  };

  const removeEvent = (id: string) => {
    updateData((prev) => ({
      ...prev,
      events: prev.events.filter((e) => e.id !== id),
    }));
  };

  return (
    <PageTransition>
      <div className="max-w-3xl mx-auto py-6 space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-serif font-bold text-[#4A3F35]">今日事件</h1>
          {isAdmin && (
            <div className="flex gap-2">
              <AnimatedButton onClick={() => setEditing(!editing)} variant="secondary" className="text-sm py-2 px-4">
                {editing ? '完成' : '编辑'}
              </AnimatedButton>
              {editing && (
                <AnimatedButton onClick={() => hasToken ? saveToGitHub() : exportDataToFile(data)} variant="primary" className="text-sm py-2 px-4" disabled={isSaving}>
                  <Save className="w-4 h-4 mr-1" />
                  {isSaving ? '保存中...' : hasToken ? '保存' : '导出'}
                </AnimatedButton>
              )}
            </div>
          )}
        </div>

        {/* Add Event Form */}
        <AnimatePresence>
          {editing && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              className="overflow-hidden"
            >
              <GlassCard className="space-y-3">
                <div className="flex gap-3">
                  <input
                    type="date"
                    value={newDate}
                    onChange={(e) => setNewDate(e.target.value)}
                    className="px-3 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-[#4A3F35] text-sm focus:outline-none focus:border-[#C89F9C]"
                  />
                  <input
                    type="text"
                    value={newEvent}
                    onChange={(e) => setNewEvent(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && addEvent()}
                    placeholder="记录今天发生了什么..."
                    className="flex-1 px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-[#4A3F35] text-sm focus:outline-none focus:border-[#C89F9C]"
                  />
                  <AnimatedButton onClick={addEvent} variant="primary" className="py-2 px-4">
                    <Plus className="w-4 h-4" />
                  </AnimatedButton>
                </div>
              </GlassCard>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Events List */}
        <div className="space-y-4">
          {data.events.map((event, index) => (
            <GlassCard key={event.id} delay={index * 0.05}>
              <div className="flex items-start gap-4">
                <div className="flex flex-col items-center gap-1 pt-1">
                  <div className="w-3 h-3 rounded-full bg-[#D4A5A5]" />
                  {index < data.events.length - 1 && <div className="w-0.5 h-full min-h-[20px] bg-[#E3D5CA] rounded-full" />}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <CalendarDays className="w-3.5 h-3.5 text-[#C89F9C]" />
                    <span className="text-xs text-[#B8A99A] font-medium">{event.date}</span>
                  </div>
                  <p className="text-[#4A3F35] leading-relaxed">{event.content}</p>
                </div>
                {editing && (
                  <button
                    onClick={() => removeEvent(event.id)}
                    className="p-2 rounded-xl text-red-400 hover:bg-red-50 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
              </div>
            </GlassCard>
          ))}

          {data.events.length === 0 && (
            <div className="text-center py-12 text-[#B8A99A]">
              <CalendarDays className="w-12 h-12 mx-auto mb-3 opacity-50" />
              <p>还没有记录任何事件</p>
            </div>
          )}
        </div>

        <div className="flex justify-center pt-4">
          <LikeButton pageKey="events" />
        </div>
        <CommentSection pagePath="events" />
      </div>
    </PageTransition>
  );
}
