import type { SiteData, User } from '@/data/initial-data';

const USERS_KEY = 'mm_users';
const AUTH_KEY = 'mm_auth';
const DATA_KEY = 'mm_site_data';
const TOKEN_KEY = 'mm_github_token';

export function getUsers(): User[] {
  try {
    const raw = localStorage.getItem(USERS_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

export function saveUsers(users: User[]): void {
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
}

export function getAuth(): { currentUser: User | null } {
  try {
    const raw = localStorage.getItem(AUTH_KEY);
    return raw ? JSON.parse(raw) : { currentUser: null };
  } catch {
    return { currentUser: null };
  }
}

export function setAuth(currentUser: User | null): void {
  localStorage.setItem(AUTH_KEY, JSON.stringify({ currentUser }));
}

export function getSiteData(): SiteData | null {
  try {
    const raw = localStorage.getItem(DATA_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

export function setSiteData(data: SiteData): void {
  localStorage.setItem(DATA_KEY, JSON.stringify(data));
}

export function getGitHubToken(): string | null {
  return localStorage.getItem(TOKEN_KEY);
}

export function setGitHubToken(token: string | null): void {
  if (token) {
    localStorage.setItem(TOKEN_KEY, token);
  } else {
    localStorage.removeItem(TOKEN_KEY);
  }
}

export function exportDataToFile(data: SiteData): void {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `site-data-${new Date().toISOString().split('T')[0]}.json`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
