export interface EventItem {
  id: string;
  date: string;
  content: string;
  image?: string;
}

export interface GalleryItem {
  id: string;
  src: string;
  title: string;
  description?: string;
}

export interface AppItem {
  id: string;
  name: string;
  description: string;
  icon: string;
  link?: string;
}

export interface TimelineItem {
  id: string;
  year: string;
  title: string;
  description: string;
  side: 'left' | 'right';
}

export interface SiteProfile {
  name: string;
  bio: string;
  avatar: string;
}

export interface SiteData {
  events: EventItem[];
  gallery: GalleryItem[];
  apps: AppItem[];
  timeline: TimelineItem[];
  profile: SiteProfile;
}

export interface User {
  username: string;
  password: string;
  role: 'admin' | 'user';
  createdAt: string;
}

