import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Heart } from 'lucide-react';
import { COUNTAPI_NAMESPACE } from '@/utils/constants';
import { useAuth } from '@/context/AuthContext';

interface LikeButtonProps {
  pageKey: string;
}

export default function LikeButton({ pageKey }: LikeButtonProps) {
  const { currentUser } = useAuth();
  const [count, setCount] = useState(0);
  const [liked, setLiked] = useState(false);
  const [animating, setAnimating] = useState(false);
  const canLike = !!currentUser;

  const storageKey = `liked_${pageKey}`;

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    setLiked(saved === 'true');

    // Get current count
    fetch(`https://api.countapi.xyz/get/${COUNTAPI_NAMESPACE}/${pageKey}`)
      .then((res) => res.json())
      .then((data) => setCount(data.value || 0))
      .catch(() => setCount(0));
  }, [pageKey, storageKey]);

  const handleLike = async () => {
    if (!canLike || liked) return;

    setAnimating(true);
    setTimeout(() => setAnimating(false), 600);

    try {
      const res = await fetch(`https://api.countapi.xyz/hit/${COUNTAPI_NAMESPACE}/${pageKey}`);
      const data = await res.json();
      setCount(data.value || 0);
      setLiked(true);
      localStorage.setItem(storageKey, 'true');
    } catch {
      // Silently fail
    }
  };

  return (
    <div className="flex items-center gap-2">
      <motion.button
        onClick={handleLike}
        disabled={!canLike}
        whileTap={canLike && !liked ? { scale: 0.8 } : undefined}
        className={`relative flex items-center gap-1.5 px-4 py-2 rounded-full transition-colors ${
          liked
            ? 'bg-red-50 text-red-500'
            : canLike
            ? 'bg-[#F5EFE6] text-[#8C7E6D] hover:bg-red-50 hover:text-red-500'
            : 'bg-[#F5EFE6]/50 text-[#B8A99A] cursor-not-allowed'
        }`}
      >
        <motion.div
          animate={animating ? { scale: [1, 1.4, 1], rotate: [0, -15, 15, 0] } : {}}
          transition={{ duration: 0.4 }}
        >
          <Heart className={`w-5 h-5 ${liked ? 'fill-current' : ''}`} />
        </motion.div>
        <span className="text-sm font-medium">{count}</span>

        {animating && (
          <motion.div
            initial={{ scale: 0, opacity: 1 }}
            animate={{ scale: 2, opacity: 0 }}
            transition={{ duration: 0.6 }}
            className="absolute inset-0 rounded-full border-2 border-red-400"
          />
        )}
      </motion.button>
      {!canLike && (
        <span className="text-xs text-[#B8A99A]">登录后可点赞</span>
      )}
    </div>
  );
}
