import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Image, AppWindow, GitBranch, CalendarDays, Sparkles } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import { useData } from '@/context/DataContext';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';

const modules = [
  { path: '/events', label: '今日事件', icon: CalendarDays, color: 'bg-[#D4A5A5]/30', iconColor: 'text-[#C89F9C]' },
  { path: '/gallery', label: '铭铭的画集', icon: Image, color: 'bg-[#C89F9C]/30', iconColor: 'text-[#B88E8B]' },
  { path: '/apps', label: '铭铭的应用', icon: AppWindow, color: 'bg-[#E3D5CA]/50', iconColor: 'text-[#8D7B68]' },
  { path: '/timeline', label: '个人世界线', icon: GitBranch, color: 'bg-[#D4A5A5]/20', iconColor: 'text-[#C89F9C]' },
];

export default function Home() {
  const navigate = useNavigate();
  const { currentUser, isAdmin } = useAuth();
  const { data } = useData();
  const latestEvent = data.events[0];

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return '早上好';
    if (hour < 18) return '下午好';
    return '晚上好';
  };

  return (
    <PageTransition>
      <div className="max-w-4xl mx-auto py-6 space-y-8">
        {/* Profile Card */}
        <GlassCard delay={0}>
          <div className="flex items-center gap-5">
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', damping: 15, delay: 0.1 }}
              className="relative"
            >
              <img
                src={data.profile.avatar}
                alt="avatar"
                className="w-20 h-20 rounded-full border-4 border-[#F5EFE6] shadow-md"
              />
              {isAdmin && (
                <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-[#C89F9C] rounded-full flex items-center justify-center">
                  <Sparkles className="w-3 h-3 text-white" />
                </div>
              )}
            </motion.div>
            <div className="flex-1">
              <h1 className="text-2xl font-serif font-bold text-[#4A3F35] mb-1">
                {getGreeting()}，{currentUser ? currentUser.username : '朋友'}
              </h1>
              <p className="text-[#8C7E6D] text-sm">{data.profile.bio}</p>
              {latestEvent && (
                <p className="text-xs text-[#B8A99A] mt-2">
                  最新动态：{latestEvent.content.slice(0, 40)}
                  {latestEvent.content.length > 40 ? '...' : ''}
                </p>
              )}
            </div>
          </div>
        </GlassCard>

        {/* Module Grid */}
        <div>
          <h2 className="text-lg font-serif font-semibold text-[#4A3F35] mb-4 px-1">探索空间</h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {modules.map((mod, index) => (
              <GlassCard
                key={mod.path}
                delay={0.1 + index * 0.08}
                onClick={() => navigate(mod.path)}
                className="flex flex-col items-center text-center py-8"
              >
                <div className={`w-14 h-14 rounded-2xl ${mod.color} flex items-center justify-center mb-3`}>
                  <mod.icon className={`w-7 h-7 ${mod.iconColor}`} />
                </div>
                <span className="text-sm font-medium text-[#4A3F35]">{mod.label}</span>
              </GlassCard>
            ))}
          </div>
        </div>

        {/* Today's Event Preview */}
        {latestEvent && (
          <div>
            <h2 className="text-lg font-serif font-semibold text-[#4A3F35] mb-4 px-1">今日事件</h2>
            <GlassCard delay={0.4} onClick={() => navigate('/events')}>
              <div className="flex items-start gap-3">
                <div className="w-1 h-full min-h-[40px] bg-[#D4A5A5] rounded-full" />
                <div>
                  <p className="text-[#4A3F35] leading-relaxed">{latestEvent.content}</p>
                  <p className="text-xs text-[#B8A99A] mt-2">{latestEvent.date}</p>
                </div>
              </div>
            </GlassCard>
          </div>
        )}
      </div>
    </PageTransition>
  );
}
