import React from 'react';
import { motion } from 'framer-motion';

interface AnimatedButtonProps {
  children: React.ReactNode;
  onClick?: () => void;
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  className?: string;
  type?: 'button' | 'submit';
  disabled?: boolean;
}

const variantStyles = {
  primary: 'bg-[#C89F9C] text-white shadow-md hover:bg-[#B88E8B]',
  secondary: 'bg-[#E3D5CA] text-[#4A3F35] hover:bg-[#D4C5B8]',
  outline: 'border-2 border-[#C89F9C] text-[#C89F9C] hover:bg-[#C89F9C] hover:text-white',
  ghost: 'text-[#8C7E6D] hover:text-[#4A3F35] hover:bg-[#F5EFE6]',
};

export default function AnimatedButton({
  children,
  onClick,
  variant = 'primary',
  className = '',
  type = 'button',
  disabled = false,
}: AnimatedButtonProps) {
  return (
    <motion.button
      type={type}
      disabled={disabled}
      whileHover={{ scale: disabled ? 1 : 1.02 }}
      whileTap={{ scale: disabled ? 1 : 0.96 }}
      onClick={onClick}
      className={`px-6 py-3 rounded-2xl font-medium transition-colors duration-200 disabled:opacity-50 disabled:cursor-not-allowed ${variantStyles[variant]} ${className}`}
    >
      {children}
    </motion.button>
  );
}
