import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, X, ImageIcon } from 'lucide-react';
import LikeButton from '@/components/Interactions/LikeButton';
import CommentSection from '@/components/Interactions/CommentSection';
import { useAuth } from '@/context/AuthContext';
import { useData } from '@/context/DataContext';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';
import AnimatedButton from '@/components/Common/AnimatedButton';
import { exportDataToFile } from '@/utils/storage';

export default function Gallery() {
  const { isAdmin } = useAuth();
  const { data, updateData, saveToGitHub, hasToken, isSaving } = useData();
  const [editing, setEditing] = useState(false);
  const [lightbox, setLightbox] = useState<string | null>(null);
  const [newImage, setNewImage] = useState({ src: '', title: '', description: '' });

  const addImage = () => {
    if (!newImage.src.trim() || !newImage.title.trim()) return;
    updateData((prev) => ({
      ...prev,
      gallery: [...prev.gallery, { id: Date.now().toString(), ...newImage }],
    }));
    setNewImage({ src: '', title: '', description: '' });
  };

  const removeImage = (id: string) => {
    updateData((prev) => ({
      ...prev,
      gallery: prev.gallery.filter((g) => g.id !== id),
    }));
  };

  return (
    <PageTransition>
      <div className="max-w-5xl mx-auto py-6 space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-serif font-bold text-[#4A3F35]">铭铭的画集</h1>
          {isAdmin && (
            <div className="flex gap-2">
              <AnimatedButton onClick={() => setEditing(!editing)} variant="secondary" className="text-sm py-2 px-4">
                {editing ? '完成' : '编辑'}
              </AnimatedButton>
              {editing && (
                <AnimatedButton onClick={() => hasToken ? saveToGitHub() : exportDataToFile(data)} variant="primary" className="text-sm py-2 px-4" disabled={isSaving}>
                  {isSaving ? '保存中...' : hasToken ? '保存' : '导出'}
                </AnimatedButton>
              )}
            </div>
          )}
        </div>

        <AnimatePresence>
          {editing && (
            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden">
              <GlassCard className="space-y-3">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                  <input type="text" value={newImage.src} onChange={(e) => setNewImage({ ...newImage, src: e.target.value })} placeholder="图片链接" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <input type="text" value={newImage.title} onChange={(e) => setNewImage({ ...newImage, title: e.target.value })} placeholder="标题" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <div className="flex gap-2">
                    <input type="text" value={newImage.description} onChange={(e) => setNewImage({ ...newImage, description: e.target.value })} placeholder="描述（可选）" className="flex-1 px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                    <AnimatedButton onClick={addImage} variant="primary" className="py-2 px-4"><Plus className="w-4 h-4" /></AnimatedButton>
                  </div>
                </div>
              </GlassCard>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="columns-1 sm:columns-2 lg:columns-3 gap-4 space-y-4">
          {data.gallery.map((item, index) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
              className="break-inside-avoid"
            >
              <div className="relative group rounded-2xl overflow-hidden shadow-sm cursor-pointer" onClick={() => setLightbox(item.src)}>
                <img src={item.src} alt={item.title} className="w-full object-cover transition-transform duration-500 group-hover:scale-105" loading="lazy" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                <div className="absolute bottom-0 left-0 right-0 p-4 translate-y-full group-hover:translate-y-0 transition-transform duration-300">
                  <p className="text-white font-medium text-sm">{item.title}</p>
                  {item.description && <p className="text-white/80 text-xs mt-0.5">{item.description}</p>}
                </div>
                {editing && (
                  <button onClick={(e) => { e.stopPropagation(); removeImage(item.id); }} className="absolute top-2 right-2 p-2 rounded-xl bg-red-500/80 text-white opacity-0 group-hover:opacity-100 transition-opacity">
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
              </div>
            </motion.div>
          ))}
        </div>

        {data.gallery.length === 0 && (
          <div className="text-center py-12 text-[#B8A99A]">
            <ImageIcon className="w-12 h-12 mx-auto mb-3 opacity-50" />
            <p>画集是空的</p>
          </div>
        )}

        <div className="flex justify-center pt-4">
          <LikeButton pageKey="gallery" />
        </div>
        <CommentSection pagePath="gallery" />
      </div>

      {/* Lightbox */}
      <AnimatePresence>
        {lightbox && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4"
            onClick={() => setLightbox(null)}
          >
            <button className="absolute top-4 right-4 p-2 text-white/80 hover:text-white"><X className="w-6 h-6" /></button>
            <motion.img initial={{ scale: 0.9 }} animate={{ scale: 1 }} exit={{ scale: 0.9 }} src={lightbox} alt="" className="max-w-full max-h-[90vh] object-contain rounded-lg" onClick={(e) => e.stopPropagation()} />
          </motion.div>
        )}
      </AnimatePresence>
    </PageTransition>
  );
}
