import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Key, Save, Check, AlertCircle } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import { setGitHubToken, getGitHubToken } from '@/utils/storage';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';
import AnimatedButton from '@/components/Common/AnimatedButton';

export default function Settings() {
  const { isAdmin } = useAuth();
  const [token, setToken] = useState(getGitHubToken() || '');
  const [saved, setSaved] = useState(false);

  if (!isAdmin) {
    return (
      <PageTransition>
        <div className="max-w-xl mx-auto py-12 text-center">
          <AlertCircle className="w-12 h-12 text-[#C89F9C] mx-auto mb-4" />
          <h2 className="text-xl font-serif font-bold text-[#4A3F35] mb-2">权限不足</h2>
          <p className="text-[#8C7E6D]">只有铭铭才能访问设置页面</p>
        </div>
      </PageTransition>
    );
  }

  const handleSave = () => {
    setGitHubToken(token.trim() || null);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <PageTransition>
      <div className="max-w-2xl mx-auto py-6 space-y-6">
        <h1 className="text-2xl font-serif font-bold text-[#4A3F35]">设置</h1>

        <GlassCard>
          <div className="flex items-center gap-3 mb-4">
            <div className="w-10 h-10 rounded-xl bg-[#E3D5CA]/50 flex items-center justify-center">
              <Key className="w-5 h-5 text-[#8D7B68]" />
            </div>
            <div>
              <h2 className="font-semibold text-[#4A3F35]">GitHub Token</h2>
              <p className="text-xs text-[#8C7E6D]">配置后可直接在网页上保存内容到仓库</p>
            </div>
          </div>

          <div className="space-y-3">
            <textarea
              value={token}
              onChange={(e) => setToken(e.target.value)}
              placeholder="ghp_xxxxxxxxxxxxxxxxxxxx"
              rows={3}
              className="w-full px-4 py-3 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm text-[#4A3F35] focus:outline-none focus:border-[#C89F9C] font-mono resize-none"
            />
            <div className="flex items-center justify-between">
              <p className="text-xs text-[#B8A99A]">Token 仅存储在本地浏览器中</p>
              <AnimatedButton onClick={handleSave} variant="primary" className="text-sm py-2 px-4">
                {saved ? <Check className="w-4 h-4 mr-1" /> : <Save className="w-4 h-4 mr-1" />}
                {saved ? '已保存' : '保存'}
              </AnimatedButton>
            </div>
          </div>
        </GlassCard>

        <GlassCard>
          <h2 className="font-semibold text-[#4A3F35] mb-2">如何获取 Token</h2>
          <ol className="text-sm text-[#8C7E6D] space-y-2 list-decimal list-inside">
            <li>访问 GitHub 并登录你的账号</li>
            <li>点击头像 → Settings → Developer settings → Personal access tokens → Tokens (classic)</li>
            <li>点击 Generate new token (classic)</li>
            <li>勾选 repo 权限，生成并复制 Token</li>
            <li>将 Token 粘贴到上方输入框并保存</li>
          </ol>
        </GlassCard>
      </div>
    </PageTransition>
  );
}
