import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import type { SiteData } from '@/data/initial-data';
import { initialData } from '@/data/initial-data';
import { getSiteData, setSiteData, getGitHubToken } from '@/utils/storage';
import { GITHUB_OWNER, GITHUB_REPO } from '@/utils/constants';

interface DataContextType {
  data: SiteData;
  updateData: (updater: (prev: SiteData) => SiteData) => void;
  saveToGitHub: () => Promise<boolean>;
  hasToken: boolean;
  isSaving: boolean;
  lastSaved: Date | null;
}

const DataContext = createContext<DataContextType | null>(null);

export function DataProvider({ children }: { children: React.ReactNode }) {
  const [data, setData] = useState<SiteData>(initialData);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const hasToken = !!getGitHubToken();

  useEffect(() => {
    const saved = getSiteData();
    if (saved) {
      setData(saved);
    }
  }, []);

  const updateData = useCallback((updater: (prev: SiteData) => SiteData) => {
    setData((prev) => {
      const next = updater(prev);
      setSiteData(next);
      return next;
    });
  }, []);

  const saveToGitHub = useCallback(async (): Promise<boolean> => {
    const token = getGitHubToken();
    if (!token) return false;

    setIsSaving(true);
    try {
      const path = 'data/site-data.json';
      const content = btoa(unescape(encodeURIComponent(JSON.stringify(data, null, 2))));

      // Get existing file SHA
      let sha: string | undefined;
      try {
        const res = await fetch(`https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`, {
          headers: { Authorization: `token ${token}` },
        });
        if (res.ok) {
          const file = await res.json();
          sha = file.sha;
        }
      } catch {
        // File may not exist yet
      }

      const body: Record<string, string> = {
        message: 'Update site data from web editor',
        content,
      };
      if (sha) body.sha = sha;

      const res = await fetch(`https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contents/${path}`, {
        method: 'PUT',
        headers: {
          Authorization: `token ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(body),
      });

      if (res.ok) {
        setLastSaved(new Date());
        return true;
      }
      return false;
    } catch {
      return false;
    } finally {
      setIsSaving(false);
    }
  }, [data]);

  return (
    <DataContext.Provider value={{ data, updateData, saveToGitHub, hasToken, isSaving, lastSaved }}>
      {children}
    </DataContext.Provider>
  );
}

export function useData() {
  const ctx = useContext(DataContext);
  if (!ctx) throw new Error('useData must be used within DataProvider');
  return ctx;
}
