import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, User, Lock, LogIn, UserPlus } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import AnimatedButton from '@/components/Common/AnimatedButton';

interface LoginModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function LoginModal({ isOpen, onClose }: LoginModalProps) {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login, register } = useAuth();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (mode === 'login') {
      const ok = login(username, password);
      if (ok) {
        onClose();
      } else {
        setError('用户名或密码错误');
      }
    } else {
      if (username.length < 3) {
        setError('用户名至少3个字符');
        return;
      }
      if (password.length < 4) {
        setError('密码至少4个字符');
        return;
      }
      const ok = register(username, password);
      if (ok) {
        onClose();
      } else {
        setError('用户名已存在或格式不正确');
      }
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/30 backdrop-blur-sm"
          onClick={onClose}
        >
          <motion.div
            initial={{ scale: 0.9, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.9, opacity: 0, y: 20 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            onClick={(e) => e.stopPropagation()}
            className="glass-card w-full max-w-md rounded-3xl p-8 shadow-2xl"
          >
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-serif font-bold text-[#4A3F35]">
                {mode === 'login' ? '欢迎回来' : '创建账号'}
              </h2>
              <button onClick={onClose} className="p-2 rounded-full hover:bg-[#F5EFE6] transition-colors">
                <X className="w-5 h-5 text-[#8C7E6D]" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-[#C89F9C]" />
                <input
                  type="text"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="用户名"
                  className="w-full pl-10 pr-4 py-3 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] focus:border-[#C89F9C] focus:outline-none focus:ring-2 focus:ring-[#C89F9C]/20 text-[#4A3F35] placeholder-[#B8A99A] transition-all"
                />
              </div>

              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-[#C89F9C]" />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="密码"
                  className="w-full pl-10 pr-4 py-3 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] focus:border-[#C89F9C] focus:outline-none focus:ring-2 focus:ring-[#C89F9C]/20 text-[#4A3F35] placeholder-[#B8A99A] transition-all"
                />
              </div>

              {error && (
                <motion.p
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="text-sm text-red-500 text-center"
                >
                  {error}
                </motion.p>
              )}

              <AnimatedButton type="submit" variant="primary" className="w-full flex items-center justify-center gap-2">
                {mode === 'login' ? <LogIn className="w-4 h-4" /> : <UserPlus className="w-4 h-4" />}
                {mode === 'login' ? '登录' : '注册'}
              </AnimatedButton>
            </form>

            <p className="mt-4 text-center text-sm text-[#8C7E6D]">
              {mode === 'login' ? '还没有账号？' : '已有账号？'}
              <button
                onClick={() => { setMode(mode === 'login' ? 'register' : 'login'); setError(''); }}
                className="ml-1 text-[#C89F9C] font-medium hover:underline"
              >
                {mode === 'login' ? '立即注册' : '去登录'}
              </button>
            </p>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
