import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { LogIn, UserPlus, Eye } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import AnimatedButton from '@/components/Common/AnimatedButton';
import LoginModal from '@/components/Auth/LoginModal';

export default function Welcome() {
  const navigate = useNavigate();
  const { currentUser } = useAuth();
  const [modalOpen, setModalOpen] = React.useState(false);
  const [modalMode, setModalMode] = React.useState<'login' | 'register'>('login');

  React.useEffect(() => {
    if (currentUser) {
      navigate('/home');
    }
  }, [currentUser, navigate]);

  const openLogin = () => {
    setModalMode('login');
    setModalOpen(true);
  };

  const openRegister = () => {
    setModalMode('register');
    setModalOpen(true);
  };

  const enterAsGuest = () => {
    navigate('/home');
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative overflow-hidden px-4">
      {/* Background decorations */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <motion.div
          animate={{ scale: [1, 1.2, 1], rotate: [0, 10, -10, 0] }}
          transition={{ duration: 20, repeat: Infinity, ease: 'linear' }}
          className="absolute -top-40 -right-40 w-96 h-96 rounded-full bg-[#D4A5A5]/20 blur-3xl"
        />
        <motion.div
          animate={{ scale: [1, 1.3, 1], rotate: [0, -10, 10, 0] }}
          transition={{ duration: 25, repeat: Infinity, ease: 'linear' }}
          className="absolute -bottom-40 -left-40 w-96 h-96 rounded-full bg-[#C89F9C]/15 blur-3xl"
        />
      </div>

      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
        className="relative z-10 text-center"
      >
        <motion.div
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ delay: 0.2, duration: 0.6 }}
          className="mb-6"
        >
          <span className="inline-block px-4 py-1.5 rounded-full bg-[#F5EFE6] text-[#8C7E6D] text-xs font-medium tracking-wide">
            欢迎来到我的空间
          </span>
        </motion.div>

        <motion.h1
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3, duration: 0.7 }}
          className="font-handwriting text-7xl md:text-8xl text-[#8D7B68] mb-4"
        >
          铭铭
        </motion.h1>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5, duration: 0.6 }}
          className="text-[#8C7E6D] text-lg mb-12 font-light"
        >
          用心记录生活的每一刻
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.7, duration: 0.6 }}
          className="flex flex-col sm:flex-row gap-4 justify-center"
        >
          <AnimatedButton onClick={openLogin} variant="primary" className="flex items-center justify-center gap-2 min-w-[160px]">
            <LogIn className="w-4 h-4" />
            登录
          </AnimatedButton>
          <AnimatedButton onClick={openRegister} variant="secondary" className="flex items-center justify-center gap-2 min-w-[160px]">
            <UserPlus className="w-4 h-4" />
            注册
          </AnimatedButton>
          <AnimatedButton onClick={enterAsGuest} variant="outline" className="flex items-center justify-center gap-2 min-w-[160px]">
            <Eye className="w-4 h-4" />
            游客模式
          </AnimatedButton>
        </motion.div>
      </motion.div>

      <LoginModal isOpen={modalOpen} onClose={() => setModalOpen(false)} />
    </div>
  );
}
