import React, { useEffect, useRef } from 'react';
import { MessageCircle } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';

interface CommentSectionProps {
  pagePath: string;
}

export default function CommentSection({ pagePath }: CommentSectionProps) {
  const { currentUser } = useAuth();
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!currentUser || !containerRef.current) return;

    // Clean up existing utterances iframe
    const existing = containerRef.current.querySelector('.utterances');
    if (existing) existing.remove();

    const script = document.createElement('script');
    script.src = 'https://utteranc.es/client.js';
    script.setAttribute('repo', 'Endermanpsps/Endermanpsps.github.io');
    script.setAttribute('issue-term', pagePath);
    script.setAttribute('theme', 'github-light');
    script.setAttribute('crossorigin', 'anonymous');
    script.async = true;

    containerRef.current.appendChild(script);

    return () => {
      if (containerRef.current) {
        const utterances = containerRef.current.querySelector('.utterances');
        if (utterances) utterances.remove();
      }
    };
  }, [currentUser, pagePath]);

  if (!currentUser) {
    return (
      <div className="glass-card rounded-2xl p-6 text-center">
        <MessageCircle className="w-8 h-8 text-[#C89F9C] mx-auto mb-2" />
        <p className="text-[#8C7E6D] text-sm">登录后即可发表评论</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <h3 className="text-lg font-serif font-semibold text-[#4A3F35]">评论</h3>
      <div ref={containerRef} className="glass-card rounded-2xl p-4 min-h-[200px]" />
    </div>
  );
}
