import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Home, Image, AppWindow, GitBranch, CalendarDays } from 'lucide-react';

const items = [
  { path: '/home', label: '主页', icon: Home },
  { path: '/events', label: '事件', icon: CalendarDays },
  { path: '/gallery', label: '画集', icon: Image },
  { path: '/apps', label: '应用', icon: AppWindow },
  { path: '/timeline', label: '世界线', icon: GitBranch },
];

export default function BottomNav() {
  const location = useLocation();

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-40 md:hidden glass-card border-t border-white/50 pb-safe">
      <div className="flex items-center justify-around h-16">
        {items.map((item) => {
          const active = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className="relative flex flex-col items-center justify-center w-16 h-full"
            >
              {active && (
                <motion.div
                  layoutId="bottom-indicator"
                  className="absolute -top-0.5 w-8 h-1 bg-[#C89F9C] rounded-full"
                  transition={{ type: 'spring', bounce: 0.2, duration: 0.6 }}
                />
              )}
              <item.icon className={`w-5 h-5 mb-0.5 transition-colors ${active ? 'text-[#C89F9C]' : 'text-[#B8A99A]'}`} />
              <span className={`text-[10px] font-medium transition-colors ${active ? 'text-[#C89F9C]' : 'text-[#B8A99A]'}`}>
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
}
