import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, GitBranch } from 'lucide-react';
import LikeButton from '@/components/Interactions/LikeButton';
import CommentSection from '@/components/Interactions/CommentSection';
import { useAuth } from '@/context/AuthContext';
import { useData } from '@/context/DataContext';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';
import AnimatedButton from '@/components/Common/AnimatedButton';
import { exportDataToFile } from '@/utils/storage';

export default function Timeline() {
  const { isAdmin } = useAuth();
  const { data, updateData, saveToGitHub, hasToken, isSaving } = useData();
  const [editing, setEditing] = useState(false);
  const [newItem, setNewItem] = useState({ year: '', title: '', description: '', side: 'left' as 'left' | 'right' });

  const addItem = () => {
    if (!newItem.year.trim() || !newItem.title.trim()) return;
    updateData((prev) => ({
      ...prev,
      timeline: [...prev.timeline, { id: Date.now().toString(), ...newItem }],
    }));
    setNewItem({ year: '', title: '', description: '', side: 'left' });
  };

  const removeItem = (id: string) => {
    updateData((prev) => ({
      ...prev,
      timeline: prev.timeline.filter((t) => t.id !== id),
    }));
  };

  return (
    <PageTransition>
      <div className="max-w-4xl mx-auto py-6 space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-serif font-bold text-[#4A3F35]">个人世界线</h1>
          {isAdmin && (
            <div className="flex gap-2">
              <AnimatedButton onClick={() => setEditing(!editing)} variant="secondary" className="text-sm py-2 px-4">
                {editing ? '完成' : '编辑'}
              </AnimatedButton>
              {editing && (
                <AnimatedButton onClick={() => hasToken ? saveToGitHub() : exportDataToFile(data)} variant="primary" className="text-sm py-2 px-4" disabled={isSaving}>
                  {isSaving ? '保存中...' : hasToken ? '保存' : '导出'}
                </AnimatedButton>
              )}
            </div>
          )}
        </div>

        <AnimatePresence>
          {editing && (
            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden">
              <GlassCard className="space-y-3">
                <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                  <input type="text" value={newItem.year} onChange={(e) => setNewItem({ ...newItem, year: e.target.value })} placeholder="年份" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <input type="text" value={newItem.title} onChange={(e) => setNewItem({ ...newItem, title: e.target.value })} placeholder="标题" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <input type="text" value={newItem.description} onChange={(e) => setNewItem({ ...newItem, description: e.target.value })} placeholder="描述" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <div className="flex gap-2">
                    <select value={newItem.side} onChange={(e) => setNewItem({ ...newItem, side: e.target.value as 'left' | 'right' })} className="flex-1 px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]">
                      <option value="left">左侧</option>
                      <option value="right">右侧</option>
                    </select>
                    <AnimatedButton onClick={addItem} variant="primary" className="py-2 px-4"><Plus className="w-4 h-4" /></AnimatedButton>
                  </div>
                </div>
              </GlassCard>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="relative">
          {/* Center line */}
          <div className="absolute left-4 md:left-1/2 top-0 bottom-0 w-0.5 bg-[#E3D5CA] md:-translate-x-px" />

          <div className="space-y-8">
            {data.timeline.map((item, index) => (
              <motion.div
                key={item.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className={`relative flex items-start ${item.side === 'left' ? 'md:flex-row-reverse' : ''} md:items-center`}
              >
                {/* Node */}
                <div className="absolute left-4 md:left-1/2 w-4 h-4 bg-[#D4A5A5] rounded-full border-4 border-[#FFFBF5] z-10 md:-translate-x-2" />

                {/* Content */}
                <div className={`ml-12 md:ml-0 md:w-1/2 ${item.side === 'left' ? 'md:pr-12 md:text-right' : 'md:pl-12'}`}>
                  <GlassCard>
                    <div className={`flex items-start gap-3 ${item.side === 'left' ? 'md:flex-row-reverse' : ''}`}>
                      <div className="flex-1">
                        <span className="text-3xl font-serif font-bold text-[#D4A5A5]/40">{item.year}</span>
                        <h3 className="font-semibold text-[#4A3F35] -mt-2">{item.title}</h3>
                        <p className="text-sm text-[#8C7E6D] mt-1">{item.description}</p>
                      </div>
                      {editing && (
                        <button onClick={() => removeItem(item.id)} className="p-2 rounded-xl text-red-400 hover:bg-red-50 transition-colors shrink-0">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </div>
                  </GlassCard>
                </div>
              </motion.div>
            ))}
          </div>
        </div>

        {data.timeline.length === 0 && (
          <div className="text-center py-12 text-[#B8A99A]">
            <GitBranch className="w-12 h-12 mx-auto mb-3 opacity-50" />
            <p>世界线还是空的</p>
          </div>
        )}

        <div className="flex justify-center pt-4">
          <LikeButton pageKey="timeline" />
        </div>
        <CommentSection pagePath="timeline" />
      </div>
    </PageTransition>
  );
}
