import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, ExternalLink, AppWindow, Scissors, FileArchive, Globe } from 'lucide-react';
import LikeButton from '@/components/Interactions/LikeButton';
import CommentSection from '@/components/Interactions/CommentSection';
import { useAuth } from '@/context/AuthContext';
import { useData } from '@/context/DataContext';
import GlassCard from '@/components/Common/GlassCard';
import PageTransition from '@/components/Common/PageTransition';
import AnimatedButton from '@/components/Common/AnimatedButton';
import { exportDataToFile } from '@/utils/storage';

const iconMap: Record<string, React.ElementType> = {
  Scissors, FileArchive, Globe, AppWindow,
};

export default function Apps() {
  const { isAdmin } = useAuth();
  const { data, updateData, saveToGitHub, hasToken, isSaving } = useData();
  const [editing, setEditing] = useState(false);
  const [newApp, setNewApp] = useState({ name: '', description: '', icon: 'AppWindow', link: '' });

  const addApp = () => {
    if (!newApp.name.trim() || !newApp.description.trim()) return;
    updateData((prev) => ({
      ...prev,
      apps: [...prev.apps, { id: Date.now().toString(), ...newApp }],
    }));
    setNewApp({ name: '', description: '', icon: 'AppWindow', link: '' });
  };

  const removeApp = (id: string) => {
    updateData((prev) => ({
      ...prev,
      apps: prev.apps.filter((a) => a.id !== id),
    }));
  };

  return (
    <PageTransition>
      <div className="max-w-3xl mx-auto py-6 space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-serif font-bold text-[#4A3F35]">铭铭的应用</h1>
          {isAdmin && (
            <div className="flex gap-2">
              <AnimatedButton onClick={() => setEditing(!editing)} variant="secondary" className="text-sm py-2 px-4">
                {editing ? '完成' : '编辑'}
              </AnimatedButton>
              {editing && (
                <AnimatedButton onClick={() => hasToken ? saveToGitHub() : exportDataToFile(data)} variant="primary" className="text-sm py-2 px-4" disabled={isSaving}>
                  {isSaving ? '保存中...' : hasToken ? '保存' : '导出'}
                </AnimatedButton>
              )}
            </div>
          )}
        </div>

        <AnimatePresence>
          {editing && (
            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden">
              <GlassCard className="space-y-3">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  <input type="text" value={newApp.name} onChange={(e) => setNewApp({ ...newApp, name: e.target.value })} placeholder="应用名称" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <input type="text" value={newApp.icon} onChange={(e) => setNewApp({ ...newApp, icon: e.target.value })} placeholder="图标名称 (如: Globe)" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <input type="text" value={newApp.link} onChange={(e) => setNewApp({ ...newApp, link: e.target.value })} placeholder="链接（可选）" className="px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                  <div className="flex gap-2">
                    <input type="text" value={newApp.description} onChange={(e) => setNewApp({ ...newApp, description: e.target.value })} placeholder="描述" className="flex-1 px-4 py-2 rounded-xl bg-[#F5EFE6] border border-[#E3D5CA] text-sm focus:outline-none focus:border-[#C89F9C]" />
                    <AnimatedButton onClick={addApp} variant="primary" className="py-2 px-4"><Plus className="w-4 h-4" /></AnimatedButton>
                  </div>
                </div>
              </GlassCard>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="space-y-4">
          {data.apps.map((app, index) => {
            const Icon = iconMap[app.icon] || AppWindow;
            return (
              <GlassCard key={app.id} delay={index * 0.05}>
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-[#E3D5CA]/50 flex items-center justify-center shrink-0">
                    <Icon className="w-6 h-6 text-[#8D7B68]" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <h3 className="font-semibold text-[#4A3F35]">{app.name}</h3>
                      {app.link && (
                        <a href={app.link} target="_blank" rel="noopener noreferrer" className="text-[#C89F9C] hover:text-[#B88E8B]">
                          <ExternalLink className="w-4 h-4" />
                        </a>
                      )}
                    </div>
                    <p className="text-sm text-[#8C7E6D] mt-0.5">{app.description}</p>
                  </div>
                  {editing && (
                    <button onClick={() => removeApp(app.id)} className="p-2 rounded-xl text-red-400 hover:bg-red-50 transition-colors shrink-0">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
              </GlassCard>
            );
          })}

          {data.apps.length === 0 && (
            <div className="text-center py-12 text-[#B8A99A]">
              <AppWindow className="w-12 h-12 mx-auto mb-3 opacity-50" />
              <p>还没有添加应用</p>
            </div>
          )}
        </div>

        <div className="flex justify-center pt-4">
          <LikeButton pageKey="apps" />
        </div>
        <CommentSection pagePath="apps" />
      </div>
    </PageTransition>
  );
}
